import{_ as e,o as l,c as r,a2 as a}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"🏭 強茂 (2481) 深度研究","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/功率離散元件研究/強茂深度研究.md","filePath":"Deep32Q知識庫/產業洞察/功率離散元件研究/強茂深度研究.md"}'),n={name:"Deep32Q知識庫/產業洞察/功率離散元件研究/強茂深度研究.md"};function s(i,t,d,o,g,h){return l(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="🏭-強茂-2481-深度研究" tabindex="-1">🏭 強茂 (2481) 深度研究 <a class="header-anchor" href="#🏭-強茂-2481-深度研究" aria-label="Permalink to &quot;🏭 強茂 (2481) 深度研究&quot;">​</a></h1><p><strong>更新日期：</strong> 2026-05-12 <strong>研究範圍：</strong> 公司簡介、產品結構、2026 成長動能、財務分析</p><hr><h2 id="_1-公司簡介" tabindex="-1">1. 公司簡介 <a class="header-anchor" href="#_1-公司簡介" aria-label="Permalink to &quot;1. 公司簡介&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">內容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>公司名稱</strong></td><td style="text-align:left;">強茂股份有限公司（Chilwee Electronics）</td></tr><tr><td style="text-align:left;"><strong>股票代號</strong></td><td style="text-align:left;">2481.TW</td></tr><tr><td style="text-align:left;"><strong>成立年份</strong></td><td style="text-align:left;">1986 年</td></tr><tr><td style="text-align:left;"><strong>總部地點</strong></td><td style="text-align:left;">台灣高雄岡山科學園區</td></tr><tr><td style="text-align:left;"><strong>公司定位</strong></td><td style="text-align:left;">台灣最大功率離散元件廠，全球二極體前十大</td></tr><tr><td style="text-align:left;"><strong>業務模式</strong></td><td style="text-align:left;">IDM（整合元件製造）— 設計、晶圓、封測一貫作業</td></tr><tr><td style="text-align:left;"><strong>全球排名</strong></td><td style="text-align:left;">功率半導體全球前 15 大，二極體全球前十大</td></tr></tbody></table><hr><h2 id="_2-產品結構分析" tabindex="-1">2. 產品結構分析 <a class="header-anchor" href="#_2-產品結構分析" aria-label="Permalink to &quot;2. 產品結構分析&quot;">​</a></h2><h3 id="營收佔比-2026-年預估" tabindex="-1">營收佔比（2026 年預估） <a class="header-anchor" href="#營收佔比-2026-年預估" aria-label="Permalink to &quot;營收佔比（2026 年預估）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">產品類別</th><th style="text-align:center;">營收佔比</th><th style="text-align:left;">特色與重點</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>二極體</strong></td><td style="text-align:center;">~40%</td><td style="text-align:left;">全球前十大，車用/工業/消費電子全覆蓋</td></tr><tr><td style="text-align:left;"><strong>MOSFET</strong></td><td style="text-align:center;">~30%（目標 2030 年 5 億美元）</td><td style="text-align:left;">低壓~中壓為主，AI+車用雙主軸</td></tr><tr><td style="text-align:left;"><strong>TVS 保護元件</strong></td><td style="text-align:center;">~15%</td><td style="text-align:left;">ESD/過壓保護，消費電子主力</td></tr><tr><td style="text-align:left;"><strong>SPS 電源供應模組</strong></td><td style="text-align:center;">~10%（新產品）</td><td style="text-align:left;">AI 伺服器電源管理，高成長潛力</td></tr><tr><td style="text-align:left;"><strong>其他</strong></td><td style="text-align:center;">~5%</td><td style="text-align:left;">穩壓器、驅動 IC 等</td></tr></tbody></table><h3 id="mosfet-發展目標-55-計劃-2026-2030" tabindex="-1">MOSFET 發展目標（55 計劃：2026-2030） <a class="header-anchor" href="#mosfet-發展目標-55-計劃-2026-2030" aria-label="Permalink to &quot;MOSFET 發展目標（55 計劃：2026-2030）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:center;">目前</th><th style="text-align:center;">目標 (2030)</th><th style="text-align:center;">CAGR</th></tr></thead><tbody><tr><td style="text-align:left;">MOSFET 營收</td><td style="text-align:center;">~$1.5 億 USD</td><td style="text-align:center;">$5 億 USD</td><td style="text-align:center;"><strong>~35%</strong></td></tr><tr><td style="text-align:left;">AI 營收佔比</td><td style="text-align:center;">4-6% (2025)</td><td style="text-align:center;">15-20%（外資估）</td><td style="text-align:center;">—</td></tr><tr><td style="text-align:left;">車用營收佔比</td><td style="text-align:center;">~35%</td><td style="text-align:center;">40%+</td><td style="text-align:center;">—</td></tr></tbody></table><hr><h2 id="_3-2026-成長動能-五大引擎" tabindex="-1">3. 2026 成長動能（五大引擎） <a class="header-anchor" href="#_3-2026-成長動能-五大引擎" aria-label="Permalink to &quot;3. 2026 成長動能（五大引擎）&quot;">​</a></h2><h3 id="_1-ai-伺服器-從-4-6-→-9-12" tabindex="-1">① AI 伺服器：從 4-6% → 9-12% <a class="header-anchor" href="#_1-ai-伺服器-從-4-6-→-9-12" aria-label="Permalink to &quot;① AI 伺服器：從 4-6% → 9-12%&quot;">​</a></h3><p><strong>關鍵進展：</strong></p><ul><li>已切入 <strong>NVIDIA GB200</strong> 供應鏈，提供二極體與功率元件</li><li>力拚 <strong>GB300</strong> 訂單（下一代產品）</li><li>2025 年底切入雲端服務供應商（CSP）的 <strong>ASIC 伺服器</strong>供應鏈</li><li>提供 MOSFET、LDO（低壓降穩壓器）、隔離驅動等關鍵元件</li></ul><p><strong>AI 應用三大領域：</strong></p><ol><li><strong>主機板</strong>：CPU/GPU VRM 電源管理</li><li><strong>電源</strong>：AC/DC、DC/DC 轉換器</li><li><strong>散熱</strong>：風扇驅動 MOSFET</li></ol><p><strong>產品升級：</strong> 48V 架構推動 MOSFET 從 30V 升級至 100V，單位價值提升 2-3 倍</p><ul><li>30V 熱插拔產品訂單已排至 <strong>10月</strong></li><li>100V 產品預計 <strong>2026 H2 量產</strong></li></ul><h3 id="_2-車用電子-營收佔比朝-40-靠攏" tabindex="-1">② 車用電子：營收佔比朝 40% 靠攏 <a class="header-anchor" href="#_2-車用電子-營收佔比朝-40-靠攏" aria-label="Permalink to &quot;② 車用電子：營收佔比朝 40% 靠攏&quot;">​</a></h3><ul><li><strong>動力轉向</strong>、<strong>HVAC</strong>（空調壓縮機）、<strong>BMS</strong>（電池管理系統）、<strong>ECU</strong>（引擎控制單元）</li><li>與 <strong>歐洲、日本 Tier 1 車廠</strong>合作推進 SiC 及高壓 MOSFET 驗證</li><li>受惠於 <strong>China+1 轉單效應</strong>：安世半導體（中資 Nexperia）地緣風險 → 客戶轉向強茂</li></ul><h3 id="_3-國際轉單效應-安世半導體事件" tabindex="-1">③ 國際轉單效應（安世半導體事件） <a class="header-anchor" href="#_3-國際轉單效應-安世半導體事件" aria-label="Permalink to &quot;③ 國際轉單效應（安世半導體事件）&quot;">​</a></h3><ul><li>Nexperia（原飛思卡爾，現中資持有）地緣政治風險升高</li><li>全球車廠/工業客戶建立在地供應鏈 → <strong>強茂成為主要受益者</strong></li><li>大陸車廠建立在地供應鏈需求增加</li></ul><h3 id="_4-交期拉長至-30-週-供不應求" tabindex="-1">④ 交期拉長至 30 週（供不應求） <a class="header-anchor" href="#_4-交期拉長至-30-週-供不應求" aria-label="Permalink to &quot;④ 交期拉長至 30 週（供不應求）&quot;">​</a></h3><ul><li>全球 MOSFET 平均交期 <strong>25 週</strong>，強茂已達 <strong>30 週</strong></li><li>反映市場需求強勁、產能緊張的結構性供需失衡</li><li>預期此缺貨態勢持續至 <strong>2026 H2</strong></li></ul><h3 id="_5-越南產能擴建-14-億元台幣" tabindex="-1">⑤ 越南產能擴建（14 億元台幣） <a class="header-anchor" href="#_5-越南產能擴建-14-億元台幣" aria-label="Permalink to &quot;⑤ 越南產能擴建（14 億元台幣）&quot;">​</a></h3><ul><li>2025 年收購越南 <strong>TOREX 95% 股權</strong></li><li>配合菲律賓封裝線，形成「中國—台灣—東南亞」製造網絡</li><li>強化全球供應鏈韌性與地緣彈性</li></ul><hr><h2 id="_4-2026-財務分析" tabindex="-1">4. 2026 財務分析 <a class="header-anchor" href="#_4-2026-財務分析" aria-label="Permalink to &quot;4. 2026 財務分析&quot;">​</a></h2><h3 id="營收與獲利預估-2026-全年" tabindex="-1">營收與獲利預估（2026 全年） <a class="header-anchor" href="#營收與獲利預估-2026-全年" aria-label="Permalink to &quot;營收與獲利預估（2026 全年）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">指標</th><th style="text-align:left;">預估數值</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全年營收</strong></td><td style="text-align:left;">年增 11.6-16.4%（雙位數）</td><td style="text-align:left;">法人預期</td></tr><tr><td style="text-align:left;"><strong>營益成長</strong></td><td style="text-align:left;">年增 40-60%（高於營收）</td><td style="text-align:left;">法人預期</td></tr><tr><td style="text-align:left;"><strong>毛利率</strong></td><td style="text-align:left;">~32.68%（Q1 創新高）</td><td style="text-align:left;">法說會</td></tr><tr><td style="text-align:left;"><strong>EPS</strong></td><td style="text-align:left;">預估區間待確認（Q1 EPS 0.75元，四年新高）</td><td style="text-align:left;">法說會</td></tr><tr><td style="text-align:left;"><strong>4月營收</strong></td><td style="text-align:left;">12.97 億台幣（y+8.8%）</td><td style="text-align:left;">公司公告</td></tr></tbody></table><h3 id="q1-2026-財務亮點" tabindex="-1">Q1 2026 財務亮點 <a class="header-anchor" href="#q1-2026-財務亮點" aria-label="Permalink to &quot;Q1 2026 財務亮點&quot;">​</a></h3><ul><li><strong>毛利率 32.68%</strong>：創下歷史新高（主要受惠於 AI 產品佔比提升、產品組合優化）</li><li><strong>EPS 0.75 元</strong>：四年來新高</li><li><strong>訂單滿至下半年</strong>：產能利用率接近飽和</li></ul><h3 id="價格調整" tabindex="-1">價格調整 <a class="header-anchor" href="#價格調整" aria-label="Permalink to &quot;價格調整&quot;">​</a></h3><ul><li>因銅及環氧樹脂成本上漲，部分產品調漲 <strong>10-15%</strong></li><li>預計在 Q2 反映在財報上</li></ul><hr><h2 id="_5-強茂競爭優勢總結" tabindex="-1">5. 強茂競爭優勢總結 <a class="header-anchor" href="#_5-強茂競爭優勢總結" aria-label="Permalink to &quot;5. 強茂競爭優勢總結&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">優勢項目</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>AI 伺服器先驅</strong></td><td style="text-align:left;">首家切入 NVIDIA GB200 的台廠功率元件供應商</td></tr><tr><td style="text-align:left;"><strong>交期領先</strong></td><td style="text-align:left;">30 週交期反映市場地位與供需優勢</td></tr><tr><td style="text-align:left;"><strong>產品組合優化</strong></td><td style="text-align:left;">AI 佔比從 4-6% → 9-12%，毛利率結構持續改善</td></tr><tr><td style="text-align:left;"><strong>車用多元化</strong></td><td style="text-align:left;">動力轉向、HVAC、BMS、ECU 多點佈局</td></tr><tr><td style="text-align:left;"><strong>China+1 紅利</strong></td><td style="text-align:left;">Nexperia 轉單最大受益者之一</td></tr><tr><td style="text-align:left;"><strong>垂直整合</strong></td><td style="text-align:left;">IDM 模式，成本控制能力強</td></tr></tbody></table><hr><h2 id="_6-風險與挑戰" tabindex="-1">6. 風險與挑戰 <a class="header-anchor" href="#_6-風險與挑戰" aria-label="Permalink to &quot;6. 風險與挑戰&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">風險項目</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>景氣循環</strong></td><td style="text-align:left;">MOSFET 歷史週期性波動，若 AI 需求放緩可能影響</td></tr><tr><td style="text-align:left;"><strong>SiC 良率</strong></td><td style="text-align:left;">SiC 產品量產仍面臨技術挑戰，良率不如國際大廠</td></tr><tr><td style="text-align:left;"><strong>中國競爭</strong></td><td style="text-align:left;">大陸功率元件廠大量擴產，低價競爭壓力</td></tr><tr><td style="text-align:left;"><strong>原材料成本</strong></td><td style="text-align:left;">銅、環氧樹脂等原材料價格波動影響毛利率</td></tr><tr><td style="text-align:left;"><strong>地緣政治</strong></td><td style="text-align:left;">中美貿易摩擦持續，供應鏈布局壓力</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>工商時報</strong> (2026-03): 強茂法說會 — AI 佔比 9-12%, 交期 30 週, 55 計劃</li><li><strong>鉅亨網</strong> (2026-03): 強茂 Q1 毛利率 32.68%, EPS 0.75 元, 訂單滿至下半年</li><li><strong>CMoney</strong> (2026-05): 強茂 AI 伺服器布局, GB200/GB300 供應鏈</li><li><strong>經濟日報</strong> (2026-05): 強茂越南產能擴建, China+1 轉單效應</li><li><strong>DIGITIMES</strong> (2026-03): 強茂 NEPCON JAPAN 展會展示 SiC MOSFET</li><li><strong>Baird / Investing.com</strong> (2026-05): 全球 MOSFET 交期數據, 強茂 30 週</li><li><strong>財報狗</strong> (2026-05): 強茂歷史財務數據</li><li><strong>CMoney</strong> (2026-05): 強茂 AI 營收佔比外資估 15 億</li></ol>',45)])])}const f=e(n,[["render",s]]);export{y as __pageData,f as default};
